  1	import * as React from 'react';
  2	import { Alert, Button } from '@patternfly/react-core';
  3	import * as _ from 'lodash';
  4	import { useTranslation } from 'react-i18next';
  5	import { EditorType, EditorToggle } from './editor-toggle';
  6	import { K8sResourceKind } from '@openshift-console/dynamic-plugin-sdk';
  7	import { asyncYAMLToJS, safeJSToYAML } from '../yaml';
  8	import { LOCAL_STORAGE_KEY_EDITOR_TYPE } from '../const';
  9	
 10	const YAML_KEY_ORDER = ['apiVerion', 'kind', 'metadata', 'spec', 'status'];
 11	export const YAML_TO_JS_OPTIONS = {
 12	  skipInvalid: true,
 13	  sortKeys: (a, b) =>
 14	    _.indexOf(YAML_KEY_ORDER, a) - _.indexOf(YAML_KEY_ORDER, b),
 15	};
 16	
 17	// Provides toggling and syncing between a form and yaml editor. The formData state is the source
 18	// of truth. Both the form editor and the yaml editor update the formData state. Here's the basic logic of this component:
 19	// In the form view:
 20	//   - formData is both rendered and updated by the form component
 21	//   - on toggle to YAML editor, yaml is parsed from current formData state.
 22	// In the YAML view:
 23	//   - on each yaml change, attempt to parse yaml to js:
 24	//       - If it fails, nothing happens. formData remains unchanged.
 25	//       - If successful, formData is updated to resulting js
 26	//   - on toggle to form view, no action needs to be taken to sync because formData has remained up to date with each yaml change
 27	//
 28	//  This means that when switching from YAML to Form, you can lose changes if the YAML editor contains unparsable YAML
 29	//  TODO Add an extra step when switching from yaml to form to warn user if they are about to lose changes.
 30	export const SyncedEditor: React.FC<SyncedEditorProps> = ({
 31	  context = { formContext: {}, yamlContext: {} },
 32	  FormEditor,
 33	  initialData = {},
 34	  onChangeEditorType = _.noop,
 35	  onChange = _.noop,
 36	  prune,
 37	  YAMLEditor,
 38	  displayConversionError,
 39	}) => {
 40	  const { formContext, yamlContext } = context;
 41	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 42	  const [formData, setFormData] = React.useState<K8sResourceKind>(initialData);
 43	  const [yaml, setYAML] = React.useState(
 44	    safeJSToYAML(initialData, 'yamlData', {
 45	      skipInvalid: true,
 46	    }),
 47	  );
 48	  const [switchError, setSwitchError] = React.useState<string | undefined>();
 49	  const [yamlWarning, setYAMLWarning] = React.useState<boolean>(false);
 50	  const [editorType, setEditorType] = React.useState<EditorType>(
 51	    (localStorage.getItem(LOCAL_STORAGE_KEY_EDITOR_TYPE) as EditorType) ||
 52	      EditorType.Form,
 53	  );
 54	
 55	  const handleFormDataChange = (newFormData: K8sResourceKind = {}) => {
 56	    if (!_.isEqual(newFormData, formData)) {
 57	      setFormData(newFormData);
 58	      onChange(newFormData);
 59	    }
 60	  };
 61	
 62	  const handleYAMLChange = (newYAML = '') => {
 63	    asyncYAMLToJS(newYAML)
 64	      .then((js) => {
 65	        setSwitchError(undefined);
 66	        handleFormDataChange(js);
 67	        setYAML(
 68	          safeJSToYAML(prune?.(formData) ?? formData, yaml, YAML_TO_JS_OPTIONS),
 69	        );
 70	      })
 71	      .catch((err) => setSwitchError(String(err)));
 72	  };
 73	
 74	  const changeEditorType = (newType: EditorType): void => {
 75	    setEditorType(newType);
 76	    localStorage.setItem(LOCAL_STORAGE_KEY_EDITOR_TYPE, newType);
 77	    onChangeEditorType(newType);
 78	  };
 79	
 80	  const handleToggleToForm = () => {
 81	    if (switchError === undefined) {
 82	      changeEditorType(EditorType.Form);
 83	    } else {
 84	      setYAMLWarning(true);
 85	    }
 86	  };
 87	
 88	  const handleToggleToYAML = () => {
 89	    setYAML(
 90	      safeJSToYAML(prune?.(formData) ?? formData, yaml, YAML_TO_JS_OPTIONS),
 91	    );
 92	    changeEditorType(EditorType.YAML);
 93	  };
 94	
 95	  const onClickYAMLWarningConfirm = () => {
 96	    setSwitchError(undefined);
 97	    setYAMLWarning(false);
 98	    changeEditorType(EditorType.Form);
 99	  };
100	
101	  const onClickYAMLWarningCancel = () => {
102	    setYAMLWarning(false);
103	  };
104	
105	  const onChangeType = (newType) => {
106	    switch (newType) {
107	      case EditorType.YAML:
108	        handleToggleToYAML();
109	        break;
110	      case EditorType.Form:
111	        handleToggleToForm();
112	        break;
113	      default:
114	        break;
115	    }
116	  };
117	
118	  return (
119	    <>
120	      <EditorToggle value={editorType} onChange={onChangeType} />
121	      {yamlWarning && (
122	        <Alert
123	          className="co-synced-editor__yaml-warning"
124	          variant="danger"
125	          isInline
126	          title={t('Invalid YAML cannot be persisted')}
127	        >
128	          {displayConversionError && <p>{switchError}</p>}
129	          <p>{t('Switching to form view will delete any invalid YAML.')}</p>
130	          <Button variant="danger" onClick={onClickYAMLWarningConfirm}>
131	            {t('Switch and delete')}
132	          </Button>
133	          &nbsp;
134	          <Button variant="secondary" onClick={onClickYAMLWarningCancel}>
135	            {t('Cancel')}
136	          </Button>
137	        </Alert>
138	      )}
139	      {editorType === EditorType.Form ? (
140	        <FormEditor
141	          formData={formData}
142	          onChange={handleFormDataChange}
143	          prune={prune}
144	          {...formContext}
145	        />
146	      ) : (
147	        <YAMLEditor
148	          initialYAML={yaml}
149	          onChange={handleYAMLChange}
150	          {...yamlContext}
151	        />
152	      )}
153	    </>
154	  );
155	};
156	
157	type FormEditorProps = {
158	  formData?: K8sResourceKind;
159	  onChange?: (data: K8sResourceKind) => void;
160	  prune?: (data: K8sResourceKind) => any;
161	};
162	
163	type YAMLEditorProps = {
164	  initialYAML?: string;
165	  onChange?: (yaml: string) => void;
166	};
167	
168	type SyncedEditorProps = {
169	  context: {
170	    formContext: { [key: string]: any };
171	    yamlContext: { [key: string]: any };
172	  };
173	  FormEditor: React.ComponentType<FormEditorProps>;
174	  initialType?: EditorType;
175	  initialData?: K8sResourceKind;
176	  onChangeEditorType?: (newType: EditorType) => void;
177	  onChange?: (data: K8sResourceKind) => void;
178	  prune?: (data: K8sResourceKind) => any;
179	  YAMLEditor: React.ComponentType<YAMLEditorProps>;
180	  lastViewUserSettingKey: string;
181	  displayConversionError?: boolean;
182	};

